def f5(s, a):
    robot_x = s[0]
    robot_r = s[3]
    wall_x = s[19]
    dx = a[0]
    return (robot_x + robot_r < wall_x) and (dx > 0)

def f8(s, a):
    robot_y = s[1]
    robot_r = s[3]
    gap_lower = s[20] + s[28] + robot_r
    dy = a[1]
    return (robot_y < gap_lower) and (dy > 0)

def f9(s, a):
    robot_y = s[1]
    robot_r = s[3]
    gap_upper = s[30] - robot_r
    dy = a[1]
    return (robot_y > gap_upper) and (dy < 0)

def f15(s, a):
    robot_x = s[0]
    target_cx = s[9] + 0.5 * s[17]
    dx = a[0]
    return (robot_x < target_cx) and (dx > 0)

def f16(s, a):
    robot_x = s[0]
    target_cx = s[9] + 0.5 * s[17]
    dx = a[0]
    return (robot_x > target_cx) and (dx < 0)

def f17(s, a):
    robot_y = s[1]
    target_cy = s[10] + 0.5 * s[18]
    dy = a[1]
    return (robot_y < target_cy) and (dy > 0)

def f18(s, a):
    robot_y = s[1]
    target_cy = s[10] + 0.5 * s[18]
    dy = a[1]
    return (robot_y > target_cy) and (dy < 0)

def f27(s, a):
    dx = a[0]
    dy = a[1]
    dtheta = a[2]
    return abs(dtheta) > (abs(dx) + abs(dy))

def f28(s, a):
    dx = a[0]
    dy = a[1]
    dtheta = a[2]
    return (abs(dx) + abs(dy)) > abs(dtheta)

def f45(s, a):
    robot_x = s[0]
    robot_r = s[3]
    wall_x = s[19]
    dx = a[0]
    return (robot_x + robot_r < wall_x) and (dx <= 0)

def f62(s, a):
    robot_y = s[1]
    robot_r = s[3]
    gap_lower = s[20] + s[28] + robot_r
    gap_upper = s[30] - robot_r
    return (robot_y >= gap_lower) and (robot_y <= gap_upper)

def f63(s, a):
    robot_y = s[1]
    robot_r = s[3]
    gap_lower = s[20] + s[28] + robot_r
    return (robot_y >= gap_lower) and ((robot_y - gap_lower) < 0.03)

def f64(s, a):
    robot_y = s[1]
    robot_r = s[3]
    gap_upper = s[30] - robot_r
    return (robot_y <= gap_upper) and ((gap_upper - robot_y) < 0.03)

def f73(s, a):
    import math
    dx = a[0]
    dy = a[1]
    dtheta = a[2]
    trans_mag = (dx ** 2 + dy ** 2) ** 0.5
    if trans_mag < 1e-8:
        return abs(dtheta) < 0.05
    motion_angle = math.atan2(dy, dx)
    return ((motion_angle > 0) and (dtheta >= -0.05)) or ((motion_angle < 0) and (dtheta <= 0.05)) or (abs(motion_angle) < 0.1)

def f74(s, a):
    dx = a[0]
    dy = a[1]
    dtheta = a[2]
    trans_mag = (dx ** 2 + dy ** 2) ** 0.5
    return (trans_mag > 0.02) and (abs(dtheta) < 0.05)
